              responseStream = new ReadableStream({
                async start(ctrl) {
                  for await (const chunk of anthRes) {
                    if (chunk.type === "content_block_delta" && chunk.delta.type === "text_delta") {
                      ctrl.enqueue(encoder.encode(chunk.delta.text));
                    }
                  }
                  ctrl.close();
                }
              });
            } else {
              throw err;
            }
